import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    demand_scores = []

    for node in unvisited_customers:
        dist = np.linalg.norm(node - cur_truck_pos)

        demand_score = dist

        for pos in all_truck_pos:
            if np.linalg.norm(node - pos) < dist:
                demand_score += 1

        growth_factor = 0.2

        for pos in np.concatenate([unvisited_customers, all_truck_pos]):
            if np.linalg.norm(node - pos) < dist:
                demand_score += growth_factor

        demand_scores.append(demand_score)

    best_node = np.argmin(demand_scores)

    return best_node

