import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    best_node = None
    min_total_distance = float('inf')

    for i, node in enumerate(unvisited_customers):
        total_distance = np.linalg.norm(cur_truck_pos - node)

        for pos in all_truck_pos:
            if np.array_equal(node, pos):
                total_distance += np.linalg.norm(cur_truck_pos - node) + np.linalg.norm(depot_pos - node)

        if total_distance < min_total_distance:
            min_total_distance = total_distance
            best_node = i

    return best_node
